+        evidence_hash: ContentHash::compute(id.as_bytes()),
+        detected_epoch: epoch(1),
+        verified_epoch: epoch(2),
+        tags: ["react", "enrichment"].iter().map(|s| s.to_string()).collect(),
+    }
